-- Finance Phase 8B: persistent property foundation and mortgage vertical slice.

ALTER TABLE public.banking_provider_financial_accounts DROP CONSTRAINT IF EXISTS banking_provider_financial_accounts_account_role_check;
ALTER TABLE public.banking_provider_financial_accounts ADD CONSTRAINT banking_provider_financial_accounts_account_role_check CHECK (account_role IN ('lending_funding','loan_receivable','interest_income','fee_income','loss_write_off','interest_expense','settlement_clearing','provider_equity','mortgage_funding_cash','mortgage_receivable','mortgage_interest_income','mortgage_fee_income','mortgage_settlement_clearing','mortgage_credit_loss_expense'));

DO $$ BEGIN CREATE TYPE public.property_owner_type AS ENUM ('player','band','company','world','provider'); EXCEPTION WHEN duplicate_object THEN NULL; END $$;
DO $$ BEGIN CREATE TYPE public.property_category AS ENUM ('residential','commercial','studio','venue','mixed_use'); EXCEPTION WHEN duplicate_object THEN NULL; END $$;
DO $$ BEGIN CREATE TYPE public.property_listing_status AS ENUM ('draft','listed_for_sale','listed_for_rent','reserved','under_offer','sold','leased','off_market'); EXCEPTION WHEN duplicate_object THEN NULL; END $$;
DO $$ BEGIN CREATE TYPE public.property_reservation_status AS ENUM ('active','completed','expired','cancelled','failed'); EXCEPTION WHEN duplicate_object THEN NULL; END $$;
DO $$ BEGIN CREATE TYPE public.mortgage_rate_type AS ENUM ('fixed','variable','tracker','discount'); EXCEPTION WHEN duplicate_object THEN NULL; END $$;
DO $$ BEGIN CREATE TYPE public.mortgage_product_status AS ENUM ('draft','active','disabled','withdrawn'); EXCEPTION WHEN duplicate_object THEN NULL; END $$;
DO $$ BEGIN CREATE TYPE public.mortgage_application_status AS ENUM ('submitted','evaluating','approved','rejected','offer_issued','offer_accepted','completed','declined','cancelled','expired'); EXCEPTION WHEN duplicate_object THEN NULL; END $$;
DO $$ BEGIN CREATE TYPE public.mortgage_offer_status AS ENUM ('issued','accepted','declined','expired','completed','withdrawn'); EXCEPTION WHEN duplicate_object THEN NULL; END $$;
DO $$ BEGIN CREATE TYPE public.mortgage_contract_status AS ENUM ('pending_activation','active','grace_period','delinquent','redeemed','settled','refinanced','defaulted','cancelled'); EXCEPTION WHEN duplicate_object THEN NULL; END $$;
DO $$ BEGIN CREATE TYPE public.mortgage_schedule_status AS ENUM ('scheduled','due','paid','partial','grace_period','late','seriously_late','final_warning','cancelled'); EXCEPTION WHEN duplicate_object THEN NULL; END $$;
DO $$ BEGIN CREATE TYPE public.security_interest_status AS ENUM ('active','released','replaced','cancelled'); EXCEPTION WHEN duplicate_object THEN NULL; END $$;

CREATE TABLE IF NOT EXISTS public.property_districts (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), city_id uuid REFERENCES public.cities(id), city_name text NOT NULL, district_name text NOT NULL, country_code char(2), created_at timestamptz NOT NULL DEFAULT timezone('utc',now()), updated_at timestamptz NOT NULL DEFAULT timezone('utc',now()), UNIQUE(city_name,district_name));
CREATE TABLE IF NOT EXISTS public.property_templates (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), template_code text NOT NULL UNIQUE, district_id uuid REFERENCES public.property_districts(id), category public.property_category NOT NULL, property_type text NOT NULL, quality int NOT NULL CHECK(quality BETWEEN 1 AND 10), size_sqm int NOT NULL CHECK(size_sqm>0), rooms int NOT NULL DEFAULT 1, bedrooms int NOT NULL DEFAULT 0, capacity int NOT NULL DEFAULT 1, base_condition int NOT NULL DEFAULT 100, prestige int NOT NULL DEFAULT 0, default_currency_code char(3) NOT NULL DEFAULT 'USD', base_valuation_minor bigint NOT NULL CHECK(base_valuation_minor>0), metadata jsonb NOT NULL DEFAULT '{}'::jsonb, created_at timestamptz NOT NULL DEFAULT timezone('utc',now()), updated_at timestamptz NOT NULL DEFAULT timezone('utc',now()));
CREATE TABLE IF NOT EXISTS public.properties (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), template_id uuid REFERENCES public.property_templates(id), city_id uuid REFERENCES public.cities(id), city_name text NOT NULL, district_id uuid REFERENCES public.property_districts(id), district_name text NOT NULL, category public.property_category NOT NULL, property_type text NOT NULL, quality int NOT NULL, size_sqm int NOT NULL, rooms int NOT NULL, bedrooms int NOT NULL DEFAULT 0, capacity int NOT NULL, condition int NOT NULL DEFAULT 100 CHECK(condition BETWEEN 0 AND 100), prestige int NOT NULL DEFAULT 0, current_valuation_minor bigint NOT NULL CHECK(current_valuation_minor>0), currency_code char(3) NOT NULL, listing_status public.property_listing_status NOT NULL DEFAULT 'off_market', owner_type public.property_owner_type NOT NULL DEFAULT 'world', owner_id uuid, occupant_type public.property_owner_type, occupant_id uuid, persistent_status text NOT NULL DEFAULT 'active', finance_status text NOT NULL DEFAULT 'unencumbered', metadata jsonb NOT NULL DEFAULT '{}'::jsonb, created_at timestamptz NOT NULL DEFAULT timezone('utc',now()), updated_at timestamptz NOT NULL DEFAULT timezone('utc',now()));
CREATE TABLE IF NOT EXISTS public.property_listings (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), property_id uuid NOT NULL REFERENCES public.properties(id), listing_type text NOT NULL CHECK(listing_type IN ('sale','rent')), status public.property_listing_status NOT NULL, price_minor bigint NOT NULL CHECK(price_minor>0), currency_code char(3) NOT NULL, seller_owner_type public.property_owner_type NOT NULL, seller_owner_id uuid, listed_at timestamptz NOT NULL DEFAULT timezone('utc',now()), closed_at timestamptz, idempotency_key text UNIQUE, metadata jsonb NOT NULL DEFAULT '{}'::jsonb);
CREATE UNIQUE INDEX IF NOT EXISTS property_listings_one_open ON public.property_listings(property_id) WHERE status IN ('listed_for_sale','listed_for_rent','reserved','under_offer');
CREATE TABLE IF NOT EXISTS public.property_ownership_history (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), property_id uuid NOT NULL REFERENCES public.properties(id), owner_type public.property_owner_type NOT NULL, owner_id uuid, started_at timestamptz NOT NULL DEFAULT timezone('utc',now()), ended_at timestamptz, purchase_transaction_id uuid, purchase_price_minor bigint, currency_code char(3), metadata jsonb NOT NULL DEFAULT '{}'::jsonb);
CREATE TABLE IF NOT EXISTS public.property_occupancies (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), property_id uuid NOT NULL REFERENCES public.properties(id), occupant_type public.property_owner_type NOT NULL, occupant_id uuid NOT NULL, use_type text, status text NOT NULL DEFAULT 'active', started_at timestamptz NOT NULL DEFAULT timezone('utc',now()), ended_at timestamptz);
CREATE TABLE IF NOT EXISTS public.property_valuations (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), property_id uuid NOT NULL REFERENCES public.properties(id), valuation_minor bigint NOT NULL, currency_code char(3) NOT NULL, valuation_source text NOT NULL, valued_at timestamptz NOT NULL DEFAULT timezone('utc',now()), metadata jsonb NOT NULL DEFAULT '{}'::jsonb);
CREATE TABLE IF NOT EXISTS public.property_permissions (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), property_id uuid NOT NULL REFERENCES public.properties(id), grantee_type public.property_owner_type NOT NULL, grantee_id uuid NOT NULL, permission_role text NOT NULL, granted_by uuid, created_at timestamptz NOT NULL DEFAULT timezone('utc',now()), revoked_at timestamptz);
CREATE TABLE IF NOT EXISTS public.property_running_costs (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), property_id uuid NOT NULL REFERENCES public.properties(id), cost_type text NOT NULL, amount_minor bigint NOT NULL CHECK(amount_minor>=0), currency_code char(3) NOT NULL, frequency text NOT NULL DEFAULT 'monthly', effective_from date NOT NULL DEFAULT CURRENT_DATE, effective_to date);
CREATE TABLE IF NOT EXISTS public.property_reservations (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), property_id uuid NOT NULL REFERENCES public.properties(id), listing_id uuid REFERENCES public.property_listings(id), applicant_type public.property_owner_type NOT NULL, applicant_id uuid NOT NULL, status public.property_reservation_status NOT NULL DEFAULT 'active', expires_at timestamptz NOT NULL, completed_at timestamptz, idempotency_key text NOT NULL UNIQUE, created_at timestamptz NOT NULL DEFAULT timezone('utc',now()));
CREATE UNIQUE INDEX IF NOT EXISTS property_reservations_one_active ON public.property_reservations(property_id) WHERE status='active';
CREATE TABLE IF NOT EXISTS public.property_purchase_transactions (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), property_id uuid NOT NULL REFERENCES public.properties(id), reservation_id uuid REFERENCES public.property_reservations(id), buyer_type public.property_owner_type NOT NULL, buyer_id uuid NOT NULL, seller_type public.property_owner_type NOT NULL, seller_id uuid, purchase_price_minor bigint NOT NULL, deposit_minor bigint NOT NULL DEFAULT 0, mortgage_principal_minor bigint NOT NULL DEFAULT 0, currency_code char(3) NOT NULL, financial_transaction_id uuid REFERENCES public.financial_transactions(id), status text NOT NULL DEFAULT 'pending', idempotency_key text NOT NULL UNIQUE, created_at timestamptz NOT NULL DEFAULT timezone('utc',now()), completed_at timestamptz);
CREATE TABLE IF NOT EXISTS public.property_leases (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), property_id uuid NOT NULL REFERENCES public.properties(id), tenant_type public.property_owner_type NOT NULL, tenant_id uuid NOT NULL, monthly_rent_minor bigint NOT NULL, deposit_minor bigint NOT NULL DEFAULT 0, currency_code char(3) NOT NULL, status text NOT NULL DEFAULT 'active', starts_on date NOT NULL, ends_on date);
CREATE TABLE IF NOT EXISTS public.property_deposits (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), property_id uuid NOT NULL REFERENCES public.properties(id), reservation_id uuid REFERENCES public.property_reservations(id), payer_type public.property_owner_type NOT NULL, payer_id uuid NOT NULL, amount_minor bigint NOT NULL, currency_code char(3) NOT NULL, source_account_id uuid REFERENCES public.financial_accounts(id), reserve_account_id uuid REFERENCES public.financial_accounts(id), status text NOT NULL DEFAULT 'reserved', transaction_id uuid REFERENCES public.financial_transactions(id), released_at timestamptz);
CREATE TABLE IF NOT EXISTS public.mortgage_products (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), provider_id uuid NOT NULL REFERENCES public.banking_providers(id), product_code text NOT NULL UNIQUE, product_name text NOT NULL, status public.mortgage_product_status NOT NULL DEFAULT 'active', currency_code char(3) NOT NULL, eligible_borrower_types public.financial_owner_type[] NOT NULL DEFAULT ARRAY['player']::public.financial_owner_type[], eligible_property_categories public.property_category[] NOT NULL DEFAULT ARRAY['residential']::public.property_category[], rate_type public.mortgage_rate_type NOT NULL DEFAULT 'fixed', annual_rate_bps int NOT NULL CHECK(annual_rate_bps>=0), stress_rate_bps int NOT NULL DEFAULT 0, min_deposit_bps int NOT NULL DEFAULT 1000, max_ltv_bps int NOT NULL DEFAULT 9000, min_term_months int NOT NULL DEFAULT 60, max_term_months int NOT NULL DEFAULT 360, fees jsonb NOT NULL DEFAULT '{}'::jsonb, allows_overpayments boolean NOT NULL DEFAULT true, variable_rate_enabled boolean NOT NULL DEFAULT false, created_at timestamptz NOT NULL DEFAULT timezone('utc',now()), updated_at timestamptz NOT NULL DEFAULT timezone('utc',now()));
CREATE TABLE IF NOT EXISTS public.mortgage_applications (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), borrower_type public.financial_owner_type NOT NULL, borrower_id uuid NOT NULL, property_id uuid NOT NULL REFERENCES public.properties(id), product_id uuid NOT NULL REFERENCES public.mortgage_products(id), requested_term_months int NOT NULL, requested_deposit_minor bigint NOT NULL, currency_code char(3) NOT NULL, status public.mortgage_application_status NOT NULL DEFAULT 'submitted', created_by_profile_id uuid REFERENCES public.profiles(id), idempotency_key text NOT NULL UNIQUE, created_at timestamptz NOT NULL DEFAULT timezone('utc',now()), updated_at timestamptz NOT NULL DEFAULT timezone('utc',now()));
CREATE TABLE IF NOT EXISTS public.mortgage_affordability_snapshots (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), application_id uuid NOT NULL UNIQUE REFERENCES public.mortgage_applications(id), source_period_start timestamptz NOT NULL, source_period_end timestamptz NOT NULL, game_time_period text NOT NULL DEFAULT '12_weeks', calculation_version text NOT NULL, verified_income_minor bigint NOT NULL DEFAULT 0, verified_cash_minor bigint NOT NULL DEFAULT 0, debt_service_minor bigint NOT NULL DEFAULT 0, running_costs_minor bigint NOT NULL DEFAULT 0, credit_score int NOT NULL DEFAULT 600, source_references jsonb NOT NULL DEFAULT '{}'::jsonb, calculated_at timestamptz NOT NULL DEFAULT timezone('utc',now()));
CREATE TABLE IF NOT EXISTS public.mortgage_underwriting_results (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), application_id uuid NOT NULL UNIQUE REFERENCES public.mortgage_applications(id), approved boolean NOT NULL, principal_minor bigint NOT NULL DEFAULT 0, ltv_bps int NOT NULL DEFAULT 0, stressed_payment_minor bigint NOT NULL DEFAULT 0, debt_service_ratio_bps int NOT NULL DEFAULT 0, max_affordable_principal_minor bigint NOT NULL DEFAULT 0, approval_reasons jsonb NOT NULL DEFAULT '[]'::jsonb, rejection_reasons jsonb NOT NULL DEFAULT '[]'::jsonb, created_at timestamptz NOT NULL DEFAULT timezone('utc',now()));
CREATE TABLE IF NOT EXISTS public.mortgage_offers (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), application_id uuid NOT NULL REFERENCES public.mortgage_applications(id), property_id uuid NOT NULL REFERENCES public.properties(id), provider_id uuid NOT NULL REFERENCES public.banking_providers(id), product_id uuid NOT NULL REFERENCES public.mortgage_products(id), purchase_price_minor bigint NOT NULL, deposit_minor bigint NOT NULL, principal_minor bigint NOT NULL, currency_code char(3) NOT NULL, rate_bps int NOT NULL, rate_type public.mortgage_rate_type NOT NULL, term_months int NOT NULL, first_payment_date date NOT NULL, scheduled_payment_minor bigint NOT NULL, total_repayment_estimate_minor bigint NOT NULL, fees jsonb NOT NULL DEFAULT '{}'::jsonb, status public.mortgage_offer_status NOT NULL DEFAULT 'issued', offer_expires_at timestamptz NOT NULL, accepted_at timestamptz, immutable_terms jsonb NOT NULL DEFAULT '{}'::jsonb, created_at timestamptz NOT NULL DEFAULT timezone('utc',now()));
CREATE TABLE IF NOT EXISTS public.mortgage_contracts (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), borrower_type public.financial_owner_type NOT NULL, borrower_id uuid NOT NULL, provider_id uuid NOT NULL REFERENCES public.banking_providers(id), product_id uuid NOT NULL REFERENCES public.mortgage_products(id), offer_id uuid NOT NULL UNIQUE REFERENCES public.mortgage_offers(id), property_id uuid NOT NULL REFERENCES public.properties(id), repayment_bank_account_id uuid REFERENCES public.bank_accounts(id), deposit_bank_account_id uuid REFERENCES public.bank_accounts(id), principal_minor bigint NOT NULL, outstanding_principal_minor bigint NOT NULL, currency_code char(3) NOT NULL, rate_bps int NOT NULL, rate_type public.mortgage_rate_type NOT NULL, term_months int NOT NULL, remaining_term_months int NOT NULL, scheduled_payment_minor bigint NOT NULL, next_payment_date date, status public.mortgage_contract_status NOT NULL DEFAULT 'pending_activation', recurring_obligation_id uuid REFERENCES public.recurring_financial_obligations(id), completion_transaction_id uuid REFERENCES public.financial_transactions(id), created_at timestamptz NOT NULL DEFAULT timezone('utc',now()), activated_at timestamptz, updated_at timestamptz NOT NULL DEFAULT timezone('utc',now()), metadata jsonb NOT NULL DEFAULT '{}'::jsonb);
CREATE TABLE IF NOT EXISTS public.mortgage_schedule_lines (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), mortgage_contract_id uuid NOT NULL REFERENCES public.mortgage_contracts(id), schedule_version int NOT NULL DEFAULT 1, instalment_number int NOT NULL, due_date date NOT NULL, opening_principal_minor bigint NOT NULL, scheduled_principal_minor bigint NOT NULL, scheduled_interest_minor bigint NOT NULL, scheduled_fee_minor bigint NOT NULL DEFAULT 0, total_due_minor bigint NOT NULL, principal_paid_minor bigint NOT NULL DEFAULT 0, interest_paid_minor bigint NOT NULL DEFAULT 0, fee_paid_minor bigint NOT NULL DEFAULT 0, amount_paid_minor bigint NOT NULL DEFAULT 0, status public.mortgage_schedule_status NOT NULL DEFAULT 'scheduled', payment_transaction_id uuid REFERENCES public.financial_transactions(id), UNIQUE(mortgage_contract_id,schedule_version,instalment_number));
CREATE TABLE IF NOT EXISTS public.mortgage_payments (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), mortgage_contract_id uuid NOT NULL REFERENCES public.mortgage_contracts(id), schedule_line_id uuid REFERENCES public.mortgage_schedule_lines(id), amount_minor bigint NOT NULL, principal_minor bigint NOT NULL DEFAULT 0, interest_minor bigint NOT NULL DEFAULT 0, fee_minor bigint NOT NULL DEFAULT 0, currency_code char(3) NOT NULL, payment_type text NOT NULL, transaction_id uuid REFERENCES public.financial_transactions(id), idempotency_key text NOT NULL UNIQUE, created_at timestamptz NOT NULL DEFAULT timezone('utc',now()), CHECK(amount_minor=principal_minor+interest_minor+fee_minor));
CREATE TABLE IF NOT EXISTS public.mortgage_payment_attempts (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), mortgage_contract_id uuid NOT NULL REFERENCES public.mortgage_contracts(id), schedule_line_id uuid REFERENCES public.mortgage_schedule_lines(id), status text NOT NULL, attempted_amount_minor bigint NOT NULL, currency_code char(3) NOT NULL, failure_reason text, idempotency_key text NOT NULL UNIQUE, created_at timestamptz NOT NULL DEFAULT timezone('utc',now()));
CREATE TABLE IF NOT EXISTS public.property_security_interests (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), property_id uuid NOT NULL REFERENCES public.properties(id), mortgage_contract_id uuid NOT NULL REFERENCES public.mortgage_contracts(id), provider_id uuid NOT NULL REFERENCES public.banking_providers(id), original_secured_amount_minor bigint NOT NULL, outstanding_secured_amount_minor bigint NOT NULL, currency_code char(3) NOT NULL, registration_date timestamptz NOT NULL DEFAULT timezone('utc',now()), priority int NOT NULL DEFAULT 1, status public.security_interest_status NOT NULL DEFAULT 'active', release_date timestamptz, release_transaction_id uuid REFERENCES public.financial_transactions(id));
CREATE UNIQUE INDEX IF NOT EXISTS property_security_one_active_priority ON public.property_security_interests(property_id,priority) WHERE status='active';
CREATE TABLE IF NOT EXISTS public.mortgage_rate_history (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), mortgage_contract_id uuid REFERENCES public.mortgage_contracts(id), product_id uuid REFERENCES public.mortgage_products(id), rate_bps int NOT NULL, effective_from date NOT NULL, effective_to date, reason text NOT NULL);
CREATE TABLE IF NOT EXISTS public.mortgage_overpayments (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), mortgage_contract_id uuid NOT NULL REFERENCES public.mortgage_contracts(id), amount_minor bigint NOT NULL, fee_minor bigint NOT NULL DEFAULT 0, currency_code char(3) NOT NULL, transaction_id uuid REFERENCES public.financial_transactions(id), schedule_version_created int, idempotency_key text NOT NULL UNIQUE, created_at timestamptz NOT NULL DEFAULT timezone('utc',now()));
CREATE TABLE IF NOT EXISTS public.mortgage_settlement_quotes (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), mortgage_contract_id uuid NOT NULL REFERENCES public.mortgage_contracts(id), outstanding_principal_minor bigint NOT NULL, accrued_interest_minor bigint NOT NULL DEFAULT 0, unpaid_fees_minor bigint NOT NULL DEFAULT 0, early_repayment_charge_minor bigint NOT NULL DEFAULT 0, release_fee_minor bigint NOT NULL DEFAULT 0, total_payable_minor bigint NOT NULL, currency_code char(3) NOT NULL, expires_at timestamptz NOT NULL, status text NOT NULL DEFAULT 'issued', idempotency_key text NOT NULL UNIQUE, created_at timestamptz NOT NULL DEFAULT timezone('utc',now()));
CREATE TABLE IF NOT EXISTS public.mortgage_settlements (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), mortgage_contract_id uuid NOT NULL REFERENCES public.mortgage_contracts(id), quote_id uuid NOT NULL REFERENCES public.mortgage_settlement_quotes(id), amount_minor bigint NOT NULL, currency_code char(3) NOT NULL, transaction_id uuid REFERENCES public.financial_transactions(id), idempotency_key text NOT NULL UNIQUE, created_at timestamptz NOT NULL DEFAULT timezone('utc',now()));
CREATE TABLE IF NOT EXISTS public.mortgage_arrears_records (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), mortgage_contract_id uuid NOT NULL REFERENCES public.mortgage_contracts(id), schedule_line_id uuid REFERENCES public.mortgage_schedule_lines(id), days_overdue int NOT NULL, unpaid_principal_minor bigint NOT NULL, unpaid_interest_minor bigint NOT NULL, unpaid_fees_minor bigint NOT NULL, missed_payment_count int NOT NULL, status text NOT NULL, derived_at timestamptz NOT NULL DEFAULT timezone('utc',now()));
CREATE TABLE IF NOT EXISTS public.mortgage_refinance_records (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), old_mortgage_contract_id uuid NOT NULL REFERENCES public.mortgage_contracts(id), new_mortgage_contract_id uuid REFERENCES public.mortgage_contracts(id), status text NOT NULL DEFAULT 'deferred', created_at timestamptz NOT NULL DEFAULT timezone('utc',now()), metadata jsonb NOT NULL DEFAULT '{"phase8b":"schema_only"}'::jsonb);
CREATE TABLE IF NOT EXISTS public.mortgage_equity_snapshots (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), mortgage_contract_id uuid NOT NULL REFERENCES public.mortgage_contracts(id), property_id uuid NOT NULL REFERENCES public.properties(id), valuation_minor bigint NOT NULL, outstanding_principal_minor bigint NOT NULL, equity_minor bigint NOT NULL, ltv_bps int NOT NULL, currency_code char(3) NOT NULL, created_at timestamptz NOT NULL DEFAULT timezone('utc',now()));
CREATE TABLE IF NOT EXISTS public.mortgage_audit_events (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), action text NOT NULL, entity_type text NOT NULL, entity_id uuid, actor_user_id uuid DEFAULT auth.uid(), provider_id uuid REFERENCES public.banking_providers(id), reason text, old_value jsonb, new_value jsonb, created_at timestamptz NOT NULL DEFAULT timezone('utc',now()));

CREATE OR REPLACE FUNCTION public.calculate_mortgage_payment_minor(p_principal_minor bigint,p_rate_bps int,p_term_months int) RETURNS bigint LANGUAGE plpgsql IMMUTABLE AS $$
DECLARE r numeric; payment numeric; BEGIN IF p_principal_minor<=0 OR p_term_months<=0 THEN RAISE EXCEPTION 'invalid mortgage calculation inputs'; END IF; IF p_rate_bps=0 THEN RETURN CEIL(p_principal_minor::numeric/p_term_months)::bigint; END IF; r:=p_rate_bps::numeric/10000/12; payment:=p_principal_minor*r/(1-power(1+r,-p_term_months)); RETURN CEIL(payment)::bigint; END $$;

CREATE OR REPLACE FUNCTION public.list_eligible_mortgage_products(p_property_id uuid) RETURNS jsonb LANGUAGE sql SECURITY DEFINER SET search_path=public AS $$
  SELECT COALESCE(jsonb_agg(jsonb_build_object('id',mp.id,'providerId',mp.provider_id,'providerName',bp.brand_name,'productName',mp.product_name,'currencyCode',mp.currency_code,'rateBps',mp.annual_rate_bps,'rateType',mp.rate_type,'minDepositBps',mp.min_deposit_bps,'maxLtvBps',mp.max_ltv_bps,'minTermMonths',mp.min_term_months,'maxTermMonths',mp.max_term_months) ORDER BY bp.brand_name,mp.product_name),'[]'::jsonb)
  FROM public.mortgage_products mp JOIN public.banking_providers bp ON bp.id=mp.provider_id JOIN public.properties p ON p.id=p_property_id
  WHERE mp.status='active' AND mp.variable_rate_enabled=false AND mp.currency_code=p.currency_code AND p.category=ANY(mp.eligible_property_categories) AND 'player'::public.financial_owner_type=ANY(mp.eligible_borrower_types);
$$;

CREATE OR REPLACE FUNCTION public.list_persistent_properties() RETURNS jsonb LANGUAGE sql SECURITY DEFINER SET search_path=public AS $$
  SELECT COALESCE(jsonb_agg(jsonb_build_object('id',p.id,'city',p.city_name,'district',p.district_name,'category',p.category,'type',p.property_type,'quality',p.quality,'sizeSqm',p.size_sqm,'rooms',p.rooms,'bedrooms',p.bedrooms,'capacity',p.capacity,'condition',p.condition,'prestige',p.prestige,'valuationMinor',p.current_valuation_minor,'currencyCode',p.currency_code,'listingStatus',p.listing_status,'financeStatus',p.finance_status,'runningCosts',COALESCE(rc.costs,'[]'::jsonb),'mortgageEligible',EXISTS(SELECT 1 FROM public.mortgage_products mp WHERE mp.status='active' AND mp.currency_code=p.currency_code AND p.category=ANY(mp.eligible_property_categories))) ORDER BY p.city_name,p.district_name,p.current_valuation_minor),'[]'::jsonb)
  FROM public.properties p LEFT JOIN LATERAL (SELECT jsonb_agg(jsonb_build_object('type',cost_type,'amountMinor',amount_minor,'currencyCode',currency_code,'frequency',frequency)) costs FROM public.property_running_costs WHERE property_id=p.id AND effective_to IS NULL) rc ON true
  WHERE p.persistent_status='active';
$$;

CREATE OR REPLACE FUNCTION public.create_mortgage_application(p_property_id uuid,p_product_id uuid,p_requested_term_months int,p_requested_deposit_minor bigint,p_currency_code char(3),p_idempotency_key text) RETURNS uuid LANGUAGE plpgsql SECURITY DEFINER SET search_path=public AS $$
DECLARE pid uuid; prop public.properties; prod public.mortgage_products; app_id uuid; BEGIN SELECT id INTO pid FROM public.profiles WHERE user_id=auth.uid() LIMIT 1; IF pid IS NULL THEN RAISE EXCEPTION 'profile required'; END IF; IF p_idempotency_key IS NULL OR length(p_idempotency_key)=0 THEN RAISE EXCEPTION 'idempotency key required'; END IF; SELECT id INTO app_id FROM public.mortgage_applications WHERE idempotency_key=p_idempotency_key; IF app_id IS NOT NULL THEN RETURN app_id; END IF; SELECT * INTO prop FROM public.properties WHERE id=p_property_id; SELECT * INTO prod FROM public.mortgage_products WHERE id=p_product_id AND status='active'; IF prod.id IS NULL THEN RAISE EXCEPTION 'mortgage product unavailable'; END IF; IF prop.id IS NULL OR prop.listing_status NOT IN ('listed_for_sale') THEN RAISE EXCEPTION 'property is not available for purchase'; END IF; IF prop.currency_code<>prod.currency_code OR prop.currency_code<>p_currency_code THEN RAISE EXCEPTION 'product/property currency mismatch'; END IF; IF p_requested_term_months NOT BETWEEN prod.min_term_months AND prod.max_term_months THEN RAISE EXCEPTION 'invalid mortgage term'; END IF; INSERT INTO public.mortgage_applications(borrower_type,borrower_id,property_id,product_id,requested_term_months,requested_deposit_minor,currency_code,created_by_profile_id,idempotency_key) VALUES('player',pid,p_property_id,p_product_id,p_requested_term_months,p_requested_deposit_minor,p_currency_code,pid,p_idempotency_key) RETURNING id INTO app_id; RETURN app_id; END $$;

CREATE OR REPLACE FUNCTION public.evaluate_mortgage_application(p_application_id uuid) RETURNS jsonb LANGUAGE plpgsql SECURITY DEFINER SET search_path=public AS $$
DECLARE app public.mortgage_applications; prop public.properties; prod public.mortgage_products; period_start timestamptz:=timezone('utc',now())-interval '12 weeks'; income bigint:=0; cash bigint:=0; running bigint:=0; principal bigint; ltv int; payment bigint; approved boolean; reasons jsonb:='[]'::jsonb; rejects jsonb:='[]'::jsonb; offer_id uuid; BEGIN SELECT * INTO app FROM public.mortgage_applications WHERE id=p_application_id FOR UPDATE; IF app.id IS NULL THEN RAISE EXCEPTION 'application not found'; END IF; PERFORM public.banking_assert_owner_access(app.borrower_type,app.borrower_id,'mortgage_application',app.requested_deposit_minor); SELECT * INTO prop FROM public.properties WHERE id=app.property_id; SELECT * INTO prod FROM public.mortgage_products WHERE id=app.product_id; SELECT COALESCE(sum(t.net_amount_minor),0) INTO income FROM public.financial_transactions t JOIN public.financial_accounts fa ON fa.id=t.destination_account_id WHERE fa.owner_type=app.borrower_type AND fa.owner_id=app.borrower_id AND t.created_at>=period_start AND t.transaction_category IN ('wage_payment','gig_payment','festival_payment','merchandise_revenue','streaming_royalty','song_release_royalty'); SELECT COALESCE(sum(current_balance_minor),0) INTO cash FROM public.financial_accounts WHERE owner_type=app.borrower_type AND owner_id=app.borrower_id AND account_status='active' AND currency_code=app.currency_code; SELECT COALESCE(sum(amount_minor),0) INTO running FROM public.property_running_costs WHERE property_id=prop.id AND frequency='monthly' AND effective_to IS NULL; principal:=prop.current_valuation_minor-app.requested_deposit_minor; IF principal<=0 THEN rejects:=rejects||jsonb_build_array('invalid_deposit'); END IF; IF cash<app.requested_deposit_minor THEN rejects:=rejects||jsonb_build_array('verified_deposit_funds_missing'); END IF; IF app.requested_deposit_minor < CEIL(prop.current_valuation_minor*prod.min_deposit_bps::numeric/10000) THEN rejects:=rejects||jsonb_build_array('minimum_deposit_not_met'); END IF; ltv:=CEIL(principal*10000.0/prop.current_valuation_minor); IF ltv>prod.max_ltv_bps THEN rejects:=rejects||jsonb_build_array('ltv_exceeds_product_limit'); END IF; payment:=public.calculate_mortgage_payment_minor(GREATEST(principal,1),prod.annual_rate_bps+prod.stress_rate_bps,app.requested_term_months); IF payment+running > GREATEST(1, FLOOR(income/3)) THEN rejects:=rejects||jsonb_build_array('stressed_payment_not_affordable'); END IF; approved:=jsonb_array_length(rejects)=0; INSERT INTO public.mortgage_affordability_snapshots(application_id,source_period_start,source_period_end,calculation_version,verified_income_minor,verified_cash_minor,running_costs_minor,source_references) VALUES(app.id,period_start,timezone('utc',now()),'phase8b_v1',income,cash,running,jsonb_build_object('income_categories',jsonb_build_array('wage_payment','gig_payment','festival_payment','merchandise_revenue','streaming_royalty','song_release_royalty'),'excluded_categories',jsonb_build_array('loan_disbursement','internal_transfer','capital_contribution','currency_conversion','refund','administrative_adjustment'))) ON CONFLICT(application_id) DO UPDATE SET calculated_at=timezone('utc',now()), verified_income_minor=EXCLUDED.verified_income_minor, verified_cash_minor=EXCLUDED.verified_cash_minor; INSERT INTO public.mortgage_underwriting_results(application_id,approved,principal_minor,ltv_bps,stressed_payment_minor,debt_service_ratio_bps,max_affordable_principal_minor,approval_reasons,rejection_reasons) VALUES(app.id,approved,GREATEST(principal,0),GREATEST(ltv,0),payment,CASE WHEN income>0 THEN CEIL((payment+running)*10000.0/income) ELSE 10000 END,GREATEST(0,income*3-running),CASE WHEN approved THEN jsonb_build_array('server_generated_snapshot','property_and_product_currency_match') ELSE '[]'::jsonb END,rejects) ON CONFLICT(application_id) DO UPDATE SET approved=EXCLUDED.approved,rejection_reasons=EXCLUDED.rejection_reasons; IF approved THEN INSERT INTO public.mortgage_offers(application_id,property_id,provider_id,product_id,purchase_price_minor,deposit_minor,principal_minor,currency_code,rate_bps,rate_type,term_months,first_payment_date,scheduled_payment_minor,total_repayment_estimate_minor,fees,offer_expires_at,immutable_terms) VALUES(app.id,prop.id,prod.provider_id,prod.id,prop.current_valuation_minor,app.requested_deposit_minor,principal,app.currency_code,prod.annual_rate_bps,prod.rate_type,app.requested_term_months,(CURRENT_DATE+interval '1 month')::date,public.calculate_mortgage_payment_minor(principal,prod.annual_rate_bps,app.requested_term_months),public.calculate_mortgage_payment_minor(principal,prod.annual_rate_bps,app.requested_term_months)*app.requested_term_months,prod.fees,timezone('utc',now())+interval '14 days',jsonb_build_object('rate_bps',prod.annual_rate_bps,'calculation_version','phase8b_v1')) RETURNING id INTO offer_id; UPDATE public.mortgage_applications SET status='offer_issued' WHERE id=app.id; ELSE UPDATE public.mortgage_applications SET status='rejected' WHERE id=app.id; END IF; RETURN jsonb_build_object('approved',approved,'offerId',offer_id,'rejectionReasons',rejects); END $$;

CREATE OR REPLACE FUNCTION public.get_mortgage_application(p_application_id uuid) RETURNS jsonb LANGUAGE sql SECURITY DEFINER SET search_path=public AS $$ SELECT to_jsonb(a) FROM public.mortgage_applications a JOIN public.profiles p ON p.id=a.borrower_id WHERE a.id=p_application_id AND a.borrower_type='player' AND p.user_id=auth.uid() $$;
CREATE OR REPLACE FUNCTION public.get_mortgage_offer(p_offer_id uuid) RETURNS jsonb LANGUAGE sql SECURITY DEFINER SET search_path=public AS $$ SELECT to_jsonb(o) FROM public.mortgage_offers o JOIN public.mortgage_applications a ON a.id=o.application_id JOIN public.profiles p ON p.id=a.borrower_id WHERE o.id=p_offer_id AND a.borrower_type='player' AND p.user_id=auth.uid() $$;
CREATE OR REPLACE FUNCTION public.decline_mortgage_offer(p_offer_id uuid) RETURNS void LANGUAGE plpgsql SECURITY DEFINER SET search_path=public AS $$ BEGIN UPDATE public.mortgage_offers o SET status='declined' FROM public.mortgage_applications a, public.profiles p WHERE o.id=p_offer_id AND a.id=o.application_id AND a.borrower_type='player' AND a.borrower_id=p.id AND p.user_id=auth.uid(); END $$;

CREATE OR REPLACE FUNCTION public.prevent_direct_secured_property_transfer() RETURNS trigger LANGUAGE plpgsql AS $$ BEGIN IF OLD.owner_id IS DISTINCT FROM NEW.owner_id OR OLD.owner_type IS DISTINCT FROM NEW.owner_type THEN IF EXISTS (SELECT 1 FROM public.property_security_interests WHERE property_id=OLD.id AND status='active') AND COALESCE(current_setting('app.authorized_property_transfer',true),'')<>'mortgage_completion' THEN RAISE EXCEPTION 'active security blocks direct property transfer'; END IF; END IF; RETURN NEW; END $$;
DROP TRIGGER IF EXISTS properties_block_secured_direct_transfer ON public.properties;
CREATE TRIGGER properties_block_secured_direct_transfer BEFORE UPDATE OF owner_type,owner_id ON public.properties FOR EACH ROW EXECUTE FUNCTION public.prevent_direct_secured_property_transfer();

DO $$ DECLARE d uuid; t uuid; bp uuid; BEGIN INSERT INTO public.property_districts(city_name,district_name,country_code) VALUES('London','Camden','GB') ON CONFLICT(city_name,district_name) DO UPDATE SET updated_at=timezone('utc',now()) RETURNING id INTO d; INSERT INTO public.property_templates(template_code,district_id,category,property_type,quality,size_sqm,rooms,bedrooms,capacity,prestige,default_currency_code,base_valuation_minor) VALUES('phase8b-camden-studio',d,'residential','Studio flat',3,38,2,1,2,4,'GBP',24000000) ON CONFLICT(template_code) DO UPDATE SET updated_at=timezone('utc',now()) RETURNING id INTO t; INSERT INTO public.properties(template_id,city_name,district_id,district_name,category,property_type,quality,size_sqm,rooms,bedrooms,capacity,condition,prestige,current_valuation_minor,currency_code,listing_status,owner_type,metadata) SELECT t,'London',d,'Camden','residential','Studio flat',3,38,2,1,2,100,4,24000000,'GBP','listed_for_sale','world',jsonb_build_object('seed','phase8b') WHERE NOT EXISTS (SELECT 1 FROM public.properties WHERE metadata->>'seed'='phase8b'); INSERT INTO public.property_running_costs(property_id,cost_type,amount_minor,currency_code) SELECT id,'maintenance',12000,'GBP' FROM public.properties WHERE metadata->>'seed'='phase8b' ON CONFLICT DO NOTHING; SELECT id INTO bp FROM public.banking_providers LIMIT 1; IF bp IS NOT NULL THEN INSERT INTO public.mortgage_products(provider_id,product_code,product_name,currency_code,annual_rate_bps,stress_rate_bps,min_deposit_bps,max_ltv_bps,min_term_months,max_term_months) VALUES(bp,'phase8b-player-fixed-gbp','Player residential fixed repayment mortgage','GBP',525,250,1000,9000,60,360) ON CONFLICT(product_code) DO NOTHING; END IF; END $$;

ALTER TABLE public.properties ENABLE ROW LEVEL SECURITY; ALTER TABLE public.property_listings ENABLE ROW LEVEL SECURITY; ALTER TABLE public.property_reservations ENABLE ROW LEVEL SECURITY; ALTER TABLE public.mortgage_products ENABLE ROW LEVEL SECURITY; ALTER TABLE public.mortgage_applications ENABLE ROW LEVEL SECURITY; ALTER TABLE public.mortgage_affordability_snapshots ENABLE ROW LEVEL SECURITY; ALTER TABLE public.mortgage_underwriting_results ENABLE ROW LEVEL SECURITY; ALTER TABLE public.mortgage_offers ENABLE ROW LEVEL SECURITY; ALTER TABLE public.mortgage_contracts ENABLE ROW LEVEL SECURITY; ALTER TABLE public.mortgage_schedule_lines ENABLE ROW LEVEL SECURITY; ALTER TABLE public.mortgage_payments ENABLE ROW LEVEL SECURITY; ALTER TABLE public.mortgage_payment_attempts ENABLE ROW LEVEL SECURITY; ALTER TABLE public.property_security_interests ENABLE ROW LEVEL SECURITY; ALTER TABLE public.mortgage_rate_history ENABLE ROW LEVEL SECURITY; ALTER TABLE public.mortgage_overpayments ENABLE ROW LEVEL SECURITY; ALTER TABLE public.mortgage_settlement_quotes ENABLE ROW LEVEL SECURITY; ALTER TABLE public.mortgage_settlements ENABLE ROW LEVEL SECURITY; ALTER TABLE public.mortgage_arrears_records ENABLE ROW LEVEL SECURITY; ALTER TABLE public.mortgage_refinance_records ENABLE ROW LEVEL SECURITY; ALTER TABLE public.mortgage_equity_snapshots ENABLE ROW LEVEL SECURITY; ALTER TABLE public.mortgage_audit_events ENABLE ROW LEVEL SECURITY;

CREATE POLICY properties_public_read ON public.properties FOR SELECT TO authenticated USING (persistent_status='active');
CREATE POLICY property_listings_public_read ON public.property_listings FOR SELECT TO authenticated USING (status IN ('listed_for_sale','listed_for_rent','reserved','under_offer'));
CREATE POLICY mortgage_products_public_read ON public.mortgage_products FOR SELECT TO authenticated USING (status='active');
CREATE POLICY mortgage_applications_own_read ON public.mortgage_applications FOR SELECT TO authenticated USING (borrower_type='player' AND EXISTS(SELECT 1 FROM public.profiles p WHERE p.id=borrower_id AND p.user_id=auth.uid()));
CREATE POLICY mortgage_offers_own_read ON public.mortgage_offers FOR SELECT TO authenticated USING (EXISTS(SELECT 1 FROM public.mortgage_applications a JOIN public.profiles p ON p.id=a.borrower_id WHERE a.id=application_id AND a.borrower_type='player' AND p.user_id=auth.uid()));
CREATE POLICY mortgage_contracts_own_read ON public.mortgage_contracts FOR SELECT TO authenticated USING (borrower_type='player' AND EXISTS(SELECT 1 FROM public.profiles p WHERE p.id=borrower_id AND p.user_id=auth.uid()));
CREATE POLICY mortgage_schedule_own_read ON public.mortgage_schedule_lines FOR SELECT TO authenticated USING (EXISTS(SELECT 1 FROM public.mortgage_contracts c JOIN public.profiles p ON p.id=c.borrower_id WHERE c.id=mortgage_contract_id AND c.borrower_type='player' AND p.user_id=auth.uid()));
CREATE POLICY mortgage_payments_own_read ON public.mortgage_payments FOR SELECT TO authenticated USING (EXISTS(SELECT 1 FROM public.mortgage_contracts c JOIN public.profiles p ON p.id=c.borrower_id WHERE c.id=mortgage_contract_id AND c.borrower_type='player' AND p.user_id=auth.uid()));

GRANT EXECUTE ON FUNCTION public.list_persistent_properties() TO authenticated;
GRANT EXECUTE ON FUNCTION public.list_eligible_mortgage_products(uuid) TO authenticated;
GRANT EXECUTE ON FUNCTION public.create_mortgage_application(uuid,uuid,int,bigint,char(3),text) TO authenticated;
GRANT EXECUTE ON FUNCTION public.evaluate_mortgage_application(uuid) TO authenticated;
GRANT EXECUTE ON FUNCTION public.get_mortgage_application(uuid) TO authenticated;
GRANT EXECUTE ON FUNCTION public.get_mortgage_offer(uuid) TO authenticated;
GRANT EXECUTE ON FUNCTION public.decline_mortgage_offer(uuid) TO authenticated;
